s3 = boto3.client("s3")
dynamodb = boto3.resource("dynamodb")
sns = boto3.client("sns")
sqs = boto3.client("sqs")


def lambda_handler(event, context):
    action = event.get("action", "noop")
    response = {"action": action, "status": "ok"}

    try:
        if action == "read_s3":
            bucket = event["bucket"]
            key = event["key"]
            obj = s3.get_object(Bucket=bucket, Key=key)
            response["body"] = obj["Body"].read().decode("utf-8")

        elif action == "write_dynamodb":
            table_name = event["table_name"]
            item = event["item"]
            table = dynamodb.Table(table_name)
            table.put_item(Item=item)
            response["message"] = "DynamoDB item written"

        elif action == "publish_sns":
            topic_arn = event["topic_arn"]
            message = event["message"]
            sns.publish(TopicArn=topic_arn, Message=message)
            response["message"] = "SNS message published"

        elif action == "send_sqs":
            queue_url = event["queue_url"]
            message_body = event["message_body"]
            sqs.send_message(QueueUrl=queue_url, MessageBody=message_body)
            response["message"] = "SQS message sent"

        else:
            response["message"] = "No action performed"

    except ClientError as e:
        response["status"] = "error"
        response["error"] = e.response.get("Error", {}).get("Message", str(e))
    except KeyError as e:
        response["status"] = "error"
        response["error"] = f"Missing required field: {str(e)}"
    except Exception as e:
        response["status"] = "error"
        response["error"] = str(e)

    return {
        "statusCode": 200 if response["status"] == "ok" else 500,
        "headers": {"Content-Type": "application/json"},
        "body": json.dumps(response),
    }